        // Function to create a movie card with click handler for trailer
        function createMovieCard(movie) {
            return `
                <div class="movie-card" data-trailer="${movie.trailer}">
                    <img src="${movie.img}" alt="${movie.title}" loading="lazy">
                    <div class="card-body">
                        <div class="card-title">${movie.title}</div>
                        <div class="card-meta">
                            <span>${movie.year}</span>
                            <span>�</span>
                            <span>${movie.genre}</span>
                        </div>
                    </div>
                </div>
            `;
        }

        // Populate a row with movie cards
        function populateRow(elementId, movies, count = 8) {
            const row = document.getElementById(elementId);
            let html = '';
            for (let i = 0; i < count; i++) {
                const movie = movies[i % movies.length];
                html += createMovieCard(movie);
            }
            row.innerHTML = html;
        }

        populateRow('trendingRow', trendingMovies, 12);
        populateRow('popularRow', popularMovies, 10);
        populateRow('newReleasesRow', newReleaseMovies, 8);

        // Trailer modal functionality
        const trailerModal = new bootstrap.Modal(document.getElementById('trailerModal'));
        const trailerIframe = document.getElementById('trailerIframe');

        document.addEventListener('click', (e) => {
            const card = e.target.closest('.movie-card');
            if (card) {
                const trailerUrl = card.dataset.trailer;
                if (trailerUrl) {
                    trailerIframe.src = trailerUrl;
                    trailerModal.show();
                }
            }
        });

        // Clear iframe when modal is hidden
        document.getElementById('trailerModal').addEventListener('hidden.bs.modal', () => {
            trailerIframe.src = '';
        });
    </script>
</body>

</html>
